// frontend/src/components/Dashboard/Dashboard.js
import React, { useState } from 'react';
import {
  Container,
  Grid,
  Box,
  AppBar,
  Toolbar,
  IconButton,
  Typography,
  Menu,
  MenuItem,
  Avatar,
  Divider,
  Button,
  useTheme,
  useMediaQuery,
  Tooltip
} from '@mui/material';
import {
  AccountCircle,
  Logout,
  Refresh,
  Sync,
  Visibility,
  VisibilityOff,
  AdminPanelSettings
} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { toast } from 'react-toastify';
import dashboardService from '../../services/dashboardService';

import StatsCards from './StatsCards';
import OpenPositions from './OpenPositions';
import ClosedOperationsTable from './ClosedOperationsTable';

import Profile from './Profile';
import FuturesBalanceCard from './FuturesBalanceCard';
import RechargeAccountCard from './RechargeAccountCard';
import CommissionBalanceCard from './CommissionBalanceCard';

const Dashboard = () => {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('sm'));
  const navigate = useNavigate();
  const { user, logout, setUser } = useAuth();

  const [anchorEl, setAnchorEl] = useState(null);
  const [showProfile, setShowProfile] = useState(false);
  const [showClosedOperations, setShowClosedOperations] = useState(false);
  const [hideValues, setHideValues] = useState(false);
  const [autoSync, setAutoSync] = useState(false);

  const handleMenu = (event) => {
    setAnchorEl(event.currentTarget);
  };

  const handleClose = () => {
    setAnchorEl(null);
  };

  const handleProfile = () => {
    setShowProfile(true);
    handleClose();
  };

  const handleLogout = async () => {
    try {
      await logout();
      navigate('/login');
    } catch (error) {
      toast.error('Erro ao fazer logout');
    }
    handleClose();
  };

  const handleSync = async () => {
    try {
      await dashboardService.syncTrades();
      toast.success('Trades sincronizados com sucesso');
    } catch (error) {
      toast.error(error.message || 'Erro ao sincronizar trades');
    }
  };

  const toggleAutoSync = async () => {
    try {
      if (autoSync) {
        await dashboardService.stopAutoSync();
        setAutoSync(false);
        toast.info('Auto-sync desativado');
      } else {
        await dashboardService.startAutoSync();
        setAutoSync(true);
        toast.success('Auto-sync ativado');
      }
    } catch (error) {
      toast.error(error.message || 'Erro ao alterar auto-sync');
    }
  };

  const handleUserUpdate = (updatedUser) => {
    setUser(updatedUser);
  };

  return (
    <Box sx={{ flexGrow: 1, minHeight: '100vh', bgcolor: 'background.default' }}>
      {/* Barra Superior */}
      <AppBar position="static" color="transparent" elevation={0}>
        <Toolbar sx={{ justifyContent: 'space-between' }}>
          {/* Espaço vazio à esquerda para balanceamento */}
          <Box sx={{ width: '120px' }} />

          {/* Conteúdo central */}
          <Box sx={{ textAlign: 'center' }}>
            <Typography variant="subtitle1" component="div" sx={{ fontSize: '1.25rem', fontWeight: 600 }}>
              Nautilus Automação
            </Typography>
            {user?.full_name && (
              <Typography variant="body2" sx={{ color: 'text.secondary', fontSize: '0.875rem' }}>
                Bem-vindo, {user.full_name}
              </Typography>
            )}
          </Box>

          {/* Botões de ação */}
          <Box sx={{ 
            display: 'flex', 
            alignItems: 'center', 
            gap: 1.5, 
            minWidth: '200px', 
            justifyContent: 'flex-end',
            flexWrap: 'wrap'
          }}>
            {user?.is_admin && (
              <Tooltip title="Painel Admin">
                <IconButton 
                  color="inherit" 
                  onClick={() => navigate('/admin')}
                  sx={{ p: 1 }}
                >
                  <AdminPanelSettings />
                </IconButton>
              </Tooltip>
            )}

            <Tooltip title="Sincronizar trades manualmente">
              <IconButton 
                onClick={handleSync} 
                color="primary"
                sx={{ 
                  p: 1,
                  border: '1px solid',
                  borderColor: 'primary.main',
                  borderRadius: 1
                }}
              >
                <Sync />
              </IconButton>
            </Tooltip>

            <Tooltip title={autoSync ? 'Desativar Auto-Sync' : 'Ativar Auto-Sync'}>
              <Button
                variant="outlined"
                color={autoSync ? 'success' : 'primary'}
                startIcon={<Refresh />}
                onClick={toggleAutoSync}
                size="small"
                sx={{
                  minWidth: '110px',
                  fontSize: '0.75rem',
                  fontWeight: 600,
                  textTransform: 'none',
                  px: 1.5,
                  py: 0.5,
                  borderRadius: 1.5
                }}
              >
                Auto-Sync {autoSync ? 'ON' : 'OFF'}
              </Button>
            </Tooltip>

            <Tooltip title={hideValues ? 'Mostrar valores' : 'Ocultar valores'}>
              <IconButton 
                onClick={() => setHideValues(!hideValues)}
                sx={{ p: 1 }}
              >
                {hideValues ? <VisibilityOff /> : <Visibility />}
              </IconButton>
            </Tooltip>

            <IconButton
              size="large"
              onClick={handleMenu}
              color="inherit"
            >
              <Avatar sx={{ width: 32, height: 32 }}>
                <AccountCircle />
              </Avatar>
            </IconButton>
          </Box>

          <Menu
            anchorEl={anchorEl}
            open={Boolean(anchorEl)}
            onClose={handleClose}
            onClick={handleClose}
          >
            <MenuItem disabled>
              <Typography variant="body2" color="textSecondary">
                {user?.email} {user?.id && `(ID: #${user.id})`}
              </Typography>
            </MenuItem>
            <MenuItem onClick={handleProfile}>
              <AccountCircle sx={{ mr: 2 }} />
              Perfil
            </MenuItem>
            <MenuItem onClick={handleLogout}>
              <Logout sx={{ mr: 2 }} />
              Sair
            </MenuItem>
          </Menu>
        </Toolbar>
      </AppBar>

      {/* Conteúdo Principal */}
      <Container maxWidth="xl">
        <Box sx={{ flexGrow: 1, py: 3 }}>
          <Grid container spacing={3}>
            {/* Cards de Estatísticas */}
            <Grid item xs={12}>
              <StatsCards hideValues={hideValues} />
            </Grid>

            {/* Saldo da Conta de Futuros */}
            <Grid item xs={12}>
              <FuturesBalanceCard hideValues={hideValues} />
            </Grid>

            {/* Cards de Gestão Financeira */}
            <Grid item xs={12} md={6} lg={4}>
              <RechargeAccountCard />
            </Grid>

            <Grid item xs={12} md={6} lg={4}>
              <CommissionBalanceCard hideValues={hideValues} />
            </Grid>

            {/* Posições Abertas */}
            <Grid item xs={12}>
              <OpenPositions user={user} hideValues={hideValues} />
            </Grid>

            {/* Operações Encerradas */}
            <Grid item xs={12}>
              <ClosedOperationsTable hideValues={hideValues} />
            </Grid>


          </Grid>
        </Box>
      </Container>

      {/* Modal de Perfil */}
      <Profile
        open={showProfile}
        onClose={() => setShowProfile(false)}
        user={user}
        onUserUpdate={handleUserUpdate}
      />

      {/* Modal de Operações Encerradas */}
      <ClosedOperationsModal
        open={showClosedOperations}
        onClose={() => setShowClosedOperations(false)}
      />
    </Box>
  );
};

export default Dashboard;
